'use strict';

/**
* Converts a half-precision floating-point number to a primitive value.
*
* @private
* @returns {number} primitive value
*/
function valueOf() { // eslint-disable-line stdlib/no-redeclare
	return this.value;  // eslint-disable-line no-invalid-this
}


// EXPORTS //

export default valueOf;
